VALUES
  ('real-estate-moex-00974', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關法律行為之標的，下列敘述何者正確？', '["甲乙約定以火星上岩石為贈與標的物，該契約有效", "甲乙約定故宮翠玉白菜為買賣標的物，該契約有效", "甲乙約定甲需於1日內完成環島健走行程，該契約有效", "甲乙婚前協議約定，婚後任一方若有出軌行為，必須支付對方新臺幣100萬元賠償費，該契約有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00975', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲為限制行為能力人，當其為法律行為時，下列何種行為無效？', '["甲未得母之允許，於父死後3個月內，具狀向法院為拋棄其繼承權之意思表示", "甲以詐術佯稱自己已成年，向乙購買機車一輛", "甲未得父母之同意，擅自接收同學拋棄的筆電一台", "甲未得父母之同意，擅自至福利社購買鉛筆"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00976', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲告知乙，若乙願意出國比賽，不管有無得名次，即贈與乙200萬元。試問甲乙間之贈與契約的附款為何？', '["期限", "條件", "負擔", "約款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00977', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲於出國遊玩期間，適逢颱風來襲，甲家的大門因此破損，門戶洞開。鄰居乙擔心甲家遭遇盜賊，乃好 心召來工匠為其修繕，支出8千元。試問乙得依下列何種法律關係向甲請求返還8千元？', '["無因管理", "侵權行為", "不當得利", "債務不履行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00978', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關契約之敘述，下列何者正確？', '["契約為事實行為的一種", "契約得因要約交錯之方式成立", "契約皆須以書面方式為之，方得以成立", "基於契約自由原則，醫生得拒絕醫治病情危急的情敵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00979', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依現行民法規定，有關違反法定要式規定之法律行為效力，下列何者應為無效？', '["會員已交付首期會款，但未訂立會單", "不動產買賣之債權契約，未經書面公證", "不動產租賃契約期限約定2年，且未以書面簽訂", "人事保證契約未以書面簽訂"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00980', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關不當得利所應返還之客體，下列何者錯誤？', '["原物所生之孳息", "受領之原物或原權利", "原物因受領人特殊能力導致之增值", "原物毀損後，受益時之價額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00981', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲欲向乙租屋3年，雙方僅用通訊軟體Line互相協商，乙已於對話中允諾，但後來丙出更高租金，於是 乙改將該屋出租給丙並交付之，後來丙得乙之同意將該屋再出租給丁，某日丁因大意未關爐火將該屋燒 毀，下列敘述何者正確？', '["乙可以向丁主張侵權行為責任", "甲可主張乙丙之租賃契約未以書面簽訂，因此無效", "丙可以向丁主張侵權行為責任", "甲可以向丙主張有優先締約權，因此乙丙之租賃契約對甲係屬無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00982', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依侵權行為請求損害賠償之說明，下列敘述何者正確？', '["純粹經濟上之損失亦屬於一種損害，與權利受損一樣，得依民法第184條第1項前段主張之", "債權亦屬於一種財產權，被侵害時，祗得依民法第184條第1項前段主張，而不得依同條項後段主張之", "我國侵權行為之保護客體僅限於權利，未及於利益", "故意以背於善良風俗之方法加損害於他人之利益，受害人亦得依侵權行為主張之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00983', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關民法第 250 條規定之違約金類型有「損害賠償總額預定違約金」與「懲罰性違約金」兩種，下列敘 述何者正確？', '["「損害賠償總額預定違約金」，倘若債務人有債務不履行發生，惟債權人所受實際損害遠低於約定之 額度時，債權人即不得請求此一違約金金額", "「懲罰性違約金」，只要債務人有債務不履行發生時，即便債權人未因此而受損害，債權人仍得請求 此一違約金金額", "「損害賠償總額預定違約金」，債務人有債務不履行發生，導致債權人受損害時，債權人除此一違約 金外，亦得請求其他損害賠償金額", "「懲罰性違約金」，債務人有債務不履行發生，導致債權人受損害時，債權人除此一違約金外，不得 請求其他損害賠償金額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
